-- Remover feeds inativos que não têm artigos associados (entradas de tentativas anteriores)
DELETE f FROM rss_feeds f
LEFT JOIN articles a ON a.feedId = f.id
WHERE f.active = 0 AND a.id IS NULL;

-- Remover o feed duplicado The Agribiz com URL sem barra final (manter o com barra)
DELETE FROM rss_feeds WHERE url = 'https://www.theagribiz.com/feed' AND name = 'The Agribiz';

-- Renomear "Agro Estadao noticia" para "Agro Estadão"
UPDATE rss_feeds SET name = 'Agro Estadão' WHERE url = 'https://agro.estadao.com.br/feed';

-- Verificar resultado final
SELECT id, name, active, fetchErrorCount, SUBSTRING(url,1,55) as url FROM rss_feeds ORDER BY active DESC, name;

